create table if not exists public.users (id uuid primary key default gen_random_uuid(), user_id text unique not null, name text not null, mobile text, role text not null default 'user' check (role in ('user','admin')), pass_hash text not null, created_at timestamptz not null default now());
create table if not exists public.transactions (id uuid primary key default gen_random_uuid(), user_id uuid not null references public.users(id) on delete cascade, amount numeric(12,2) not null, note text, created_by uuid references public.users(id) on delete set null, created_at timestamptz not null default now());
create or replace view public.user_balances as select u.id, u.user_id, u.name, u.role, coalesce(sum(t.amount),0)::numeric(12,2) as balance from public.users u left join public.transactions t on t.user_id=u.id group by u.id,u.user_id,u.name,u.role;
create table if not exists public.withdraw_requests (id uuid primary key default gen_random_uuid(), user_id uuid not null references public.users(id) on delete cascade, amount numeric(12,2) not null, method text not null check (method in ('bKash','Nagad')), payout_number text not null, note text, status text not null default 'pending' check (status in ('pending','approved','rejected')), admin_note text, created_at timestamptz not null default now(), decided_at timestamptz);
